ext:createCollection.ext:options:
{
    validator: {
        $jsonSchema: {
            bsonType: "object",
            required: ["crid", "requestApi", "createdAt"],
            properties: {
                crid:           { bsonType: "string",  description: "Correlation/trace ID" },
                requestId:      { bsonType: "string",  description: "Request identifier" },
                requestApi:     { bsonType: "string",  description: "API method signature" },
                request:        { bsonType: "string",  description: "Serialized request body" },
                response:       { bsonType: "string",  description: "Serialized response body" },
                httpStatusCode: { bsonType: "string",  description: "HTTP status code" },
                environment:    { bsonType: "string",  description: "Active environment" },
                createdDate:    { bsonType: "string",  description: "Record creation timestamp" },
                updatedDate:    { bsonType: "string",  description: "Record update timestamp" }
            }
        }
    },
    validationLevel: "moderate",
    validationAction: "warn"
}
